// Assemble the GPT analysis prompt from transcript + extraction config
const transcript = $('Fetch Transcript').item.json.body || $('Fetch Transcript').item.json;
const systemPrompt = $('Fetch Extraction Config').item.json.system_prompt;
const sessionId = $('Webhook Trigger').item.json.session_id;
const clientId = $('Webhook Trigger').item.json.client_id;

return [{
  json: {
    session_id: sessionId,
    client_id: clientId,
    system_prompt: systemPrompt,
    user_message: `Transcript:\n\n${transcript}`,
    transcript_length: (typeof transcript === 'string' ? transcript : JSON.stringify(transcript)).length
  }
}];

// Parse GPT response and build callback payload
const gptResponse = $input.item.json.message?.content || $input.item.json.choices?.[0]?.message?.content || '';
const sessionId = $('Assemble Prompt').item.json.session_id;

// Check for n8n error (continueOnFail=true passes error as json.error)
if ($input.item.json.error) {
  return [{
    json: {
      _gpt_failed: true,
      session_id: sessionId,
      error: `GPT analysis failed: ${JSON.stringify($input.item.json.error)}`
    }
  }];
}

let facts = {};
let summary = '';
let parseFailed = false;
let parseError = null;

try {
  const parsed = typeof gptResponse === 'string' ? JSON.parse(gptResponse) : gptResponse;
  summary = parsed.summary || '';
  const { summary: _s, ...rest } = parsed;
  facts = rest;
} catch (e) {
  parseFailed = true;
  parseError = `Failed to parse GPT response: ${e.message}`;
}

if (parseFailed) {
  return [{
    json: {
      _gpt_failed: true,
      session_id: sessionId,
      error: parseError
    }
  }];
}

return [{
  json: {
    _gpt_failed: false,
    session_id: sessionId,
    summary,
    facts
  }
}];
